+  }
+
+  /**
+   * Shutdown swarm gracefully
+   */
+  async shutdown(): Promise<void> {
+    console.log('[SwarmManager] Shutting down swarm...');
+
+    // Stop timers
+    if (this.healthCheckTimer) {
