+        );
+      } catch (error) {
+        console.warn('[SwarmManager] Error executing shutdown hooks:', error);
+      }
+    }
+
+    this.emit('swarm:shutdown');
+
+    console.log('[SwarmManager] Swarm shutdown complete');
+  }
+}

